from pydantic import BaseModel, EmailStr, validator
from typing import Optional

class UserBase(BaseModel):
    name: str
    email: EmailStr

    @validator("email")
    def validate_nmims_email(cls, v):
        if not v.endswith("@nmims.in"):
            raise ValueError("Only NMIMS email IDs are allowed")
        return v


class UserCreate(UserBase):
    password: str


class UserResponse(UserBase):
    id: Optional[str]
    role: str = "student"
    wallet_balance: int = 0   # ✅ NEW

    class Config:
        orm_mode = True
